import{_ as a,o as t,c as l,a2 as i}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Claude Code Practices","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/tooling/claude-code.md","filePath":"ai-native/tooling/claude-code.md"}'),d={name:"ai-native/tooling/claude-code.md"};function o(r,e,c,n,s,h){return t(),l("div",null,[...e[0]||(e[0]=[i(`<h1 id="claude-code-practices" tabindex="-1">Claude Code Practices <a class="header-anchor" href="#claude-code-practices" aria-label="Permalink to &quot;Claude Code Practices&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>最后核对：2026-06-15</strong></p><p>本指南记录 Claude Code 的宿主差异。跨宿主长期规则仍以项目 <code>AGENTS.md</code> 和项目 Skill 真源为主。</p><h2 id="推荐实践" tabindex="-1">推荐实践 <a class="header-anchor" href="#推荐实践" aria-label="Permalink to &quot;推荐实践&quot;">​</a></h2><h3 id="_1-先给-agent-一个可执行的验证信号" tabindex="-1">1. 先给 Agent 一个可执行的验证信号 <a class="header-anchor" href="#_1-先给-agent-一个可执行的验证信号" aria-label="Permalink to &quot;1. 先给 Agent 一个可执行的验证信号&quot;">​</a></h3><p>测试、构建退出码、Lint、Fixture Diff 或 UI 截图都可以构成验证信号。Prompt 应要求 Claude Code 运行检查、读取结果并迭代，而不是只生成代码。</p><h3 id="_2-大任务采用-explore、plan、implement、verify" tabindex="-1">2. 大任务采用 Explore、Plan、Implement、Verify <a class="header-anchor" href="#_2-大任务采用-explore、plan、implement、verify" aria-label="Permalink to &quot;2. 大任务采用 Explore、Plan、Implement、Verify&quot;">​</a></h3><p>规划适合不熟悉的代码、跨文件改动和方案不确定的任务。小而明确的修改可以直接执行。</p><p>如果需求仍然模糊，先让 Claude Code 访谈需求并形成自包含 Spec，再用干净会话执行。</p><h3 id="_3-保持-claude-md-简短" tabindex="-1">3. 保持 <code>CLAUDE.md</code> 简短 <a class="header-anchor" href="#_3-保持-claude-md-简短" aria-label="Permalink to &quot;3. 保持 \`CLAUDE.md\` 简短&quot;">​</a></h3><p><code>CLAUDE.md</code> 只保存每次会话都需要、且无法从代码直接推断的内容，例如：</p><ul><li>特殊构建和测试命令</li><li>与默认不同的代码约定</li><li>仓库礼仪和关键架构决策</li><li>环境陷阱和明确禁止事项</li></ul><p>项目采用多宿主时，推荐：</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># CLAUDE.md</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Read @AGENTS.md first.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Use the project skills referenced there for task-specific workflows.</span></span></code></pre></div><p>宿主专属差异可以继续写在 <code>CLAUDE.md</code>，不要复制 <code>AGENTS.md</code> 全文。个人项目备注进入 <code>CLAUDE.local.md</code> 并加入 <code>.gitignore</code>。</p><h3 id="_4-按职责选择扩展机制" tabindex="-1">4. 按职责选择扩展机制 <a class="header-anchor" href="#_4-按职责选择扩展机制" aria-label="Permalink to &quot;4. 按职责选择扩展机制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>需求</th><th>机制</th></tr></thead><tbody><tr><td>每次会话都需要的规则</td><td><code>CLAUDE.md</code></td></tr><tr><td>按需加载的领域知识和工作流</td><td>Skill</td></tr><tr><td>隔离研究或专项审查</td><td>Subagent</td></tr><tr><td>必须执行、不能靠模型记住的动作</td><td>Hook</td></tr><tr><td>外部系统实时数据和操作</td><td>MCP 或专用 CLI</td></tr><tr><td>可安装的一组能力</td><td>Plugin</td></tr></tbody></table><h3 id="_5-主动管理上下文" tabindex="-1">5. 主动管理上下文 <a class="header-anchor" href="#_5-主动管理上下文" aria-label="Permalink to &quot;5. 主动管理上下文&quot;">​</a></h3><ul><li>不相关任务使用新会话或 <code>/clear</code></li><li>长任务在 Compact 时保留修改文件、关键决策和验证命令</li><li>大规模代码探索交给 Subagent，主上下文只接收结论</li><li>同一问题反复纠偏后，整理已知条件并从干净上下文重试</li></ul><p>上下文越长不代表信息越充分。只保留当前决策需要的信息。</p><h3 id="_6-权限与自动化分级" tabindex="-1">6. 权限与自动化分级 <a class="header-anchor" href="#_6-权限与自动化分级" aria-label="Permalink to &quot;6. 权限与自动化分级&quot;">​</a></h3><p>常用且低风险的命令可以精确 Allowlist；文件系统和网络访问由 Sandbox 限制。对删除、发布、迁移、授权和外部写操作保留人工确认。</p><p>Hook 适合零例外规则，例如编辑后执行 Lint 或禁止修改受保护目录。建议先在 Prompt 中验证流程稳定，再升级为 Hook。</p><h3 id="_7-使用独立上下文审查" tabindex="-1">7. 使用独立上下文审查 <a class="header-anchor" href="#_7-使用独立上下文审查" aria-label="Permalink to &quot;7. 使用独立上下文审查&quot;">​</a></h3><p>实现与审查分开：</p><ul><li>Writer 会话负责实现和自测</li><li>Reviewer 会话基于 Diff、需求和测试证据寻找反例</li></ul><p>并行修改应使用独立 Git Worktree，避免多个会话写入同一工作区。</p><h3 id="_8-自动化输出必须可解析" tabindex="-1">8. 自动化输出必须可解析 <a class="header-anchor" href="#_8-自动化输出必须可解析" aria-label="Permalink to &quot;8. 自动化输出必须可解析&quot;">​</a></h3><p>在 CI 或脚本中使用非交互模式时，选择 JSON 或流式 JSON，并明确超时、退出码和允许的工具。自动化任务不应依赖自然语言中的模糊“成功”。</p><h2 id="不推荐" tabindex="-1">不推荐 <a class="header-anchor" href="#不推荐" aria-label="Permalink to &quot;不推荐&quot;">​</a></h2><ul><li>把教程、API 全文和文件清单塞入 <code>CLAUDE.md</code></li><li>在无验证信号时让 Agent 长时间无人值守</li><li>用同一会话完成实现、论证和最终审查</li><li>为减少确认而直接放开所有 Bash 或外部写权限</li><li>在 <code>CLAUDE.md</code> 和 <code>AGENTS.md</code> 长期维护两份相同规则</li></ul><h2 id="采用清单" tabindex="-1">采用清单 <a class="header-anchor" href="#采用清单" aria-label="Permalink to &quot;采用清单&quot;">​</a></h2><ul><li>[ ] <code>CLAUDE.md</code> 是短入口而非知识仓库</li><li>[ ] 项目公共规则指向 <code>AGENTS.md</code></li><li>[ ] 重复工作使用 Skill，强制动作使用 Hook</li><li>[ ] 大型探索不会污染主要实现上下文</li><li>[ ] 并行会话使用隔离 Worktree</li><li>[ ] 自动化输出和完成条件可机器解析</li></ul><h2 id="官方参考" tabindex="-1">官方参考 <a class="header-anchor" href="#官方参考" aria-label="Permalink to &quot;官方参考&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/en/best-practices" target="_blank" rel="noreferrer">Best practices for Claude Code</a></li><li><a href="https://code.claude.com/docs/en/memory" target="_blank" rel="noreferrer">How Claude remembers your project</a></li><li><a href="https://code.claude.com/docs/en/hooks-guide" target="_blank" rel="noreferrer">Automate actions with hooks</a></li></ul>`,36)])])}const m=a(d,[["render",o]]);export{u as __pageData,m as default};
